import React, { useState } from "react";
import "./DeadlineModal.scss";

export function DeadlineModal({ courses, deadline, onSave, onClose, preselectedCourseId }: any) {
  const [taskName, setTaskName] = useState(deadline?.taskName || "");
  const [courseId, setCourseId] = useState(deadline?.courseId || preselectedCourseId || "");
  const [priority, setPriority] = useState(deadline?.priority || "medium");
  const [dueDate, setDueDate] = useState(deadline?.dueDate ? new Date(deadline.dueDate).toISOString().split('T')[0] : "");

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!taskName || !courseId || !dueDate) {
        alert("Please fill all fields!");
        return;
    }
    onSave({ taskName, courseId, priority, dueDate: new Date(dueDate), status: "upcoming" });
    onClose();
  };

  return (
    <div className="deadline-modal-overlay" onClick={onClose}>
      <div className="deadline-modal" onClick={(e) => e.stopPropagation()}>
        <div className="deadline-modal__header">
          <h2>{deadline ? "Edit" : "Add New"} Deadline</h2>
          <button onClick={onClose} className="close-x">×</button>
        </div>

        <form onSubmit={handleSubmit} className="deadline-modal__form">
          <div className="form-group">
            <label>Task Name *</label>
            <input type="text" value={taskName} onChange={(e) => setTaskName(e.target.value)} required />
          </div>

          <div className="form-group">
            <label>Course *</label>
            <div className="chip-group">
              {courses.map((c: any) => (
                <button 
                  key={c.id} type="button" 
                  className={`chip ${courseId === c.id ? "active" : ""}`}
                  onClick={() => setCourseId(c.id)}
                >
                  {c.title}
                </button>
              ))}
            </div>
          </div>

          <div className="form-group">
            <label>Priority *</label>
            <div className="chip-group">
              {["low", "medium", "high"].map((p) => (
                <button 
                  key={p} type="button" 
                  className={`chip priority-${p} ${priority === p ? "active" : ""}`}
                  onClick={() => setPriority(p)}
                >
                  {p}
                </button>
              ))}
            </div>
          </div>

          <div className="form-group">
            <label>Due Date *</label>
            <input type="date" value={dueDate} onChange={(e) => setDueDate(e.target.value)} required />
          </div>

          <div className="deadline-modal__actions">
            <button type="button" onClick={onClose} className="btn-cancel">Cancel</button>
            <button type="submit" className="btn-save">Save changes</button>
          </div>
        </form>
      </div>
    </div>
  );
}
